// ── Build HTML dashboard ──────────────────────────────────────────────
const tracker  = $('Get tracker data').first().json;
const pipeline = $('Get pipeline data').first().json;
const reports  = $('Get reports list').first().json;

const rows    = tracker.rows || [];
const pending = pipeline.pending || [];
const reps    = reports.reports || [];

// ── Status counts ──────────────────────────────────────────────────────
const statusCounts = {};
for (const r of rows) {
  const s = r.status || 'Unknown';
  statusCounts[s] = (statusCounts[s] || 0) + 1;
}

// Score distribution
const scores = rows.map(r => parseFloat(r.score)).filter(s => !isNaN(s));
const avgScore = scores.length ? (scores.reduce((a, b) => a + b, 0) / scores.length).toFixed(2) : 'N/A';
const highScore = rows.filter(r => parseFloat(r.score) >= 3.8).length;

// Recent activity (last 10)
const recent = [...rows].reverse().slice(0, 10);

const now = new Date().toISOString().replace('T', ' ').slice(0, 19) + ' UTC';

// ── Status badge color ─────────────────────────────────────────────────
const badgeColor = s => ({
  Applied: '#3b82f6', Interview: '#8b5cf6', Offer: '#10b981',
  Rejected: '#ef4444', Discarded: '#6b7280', SKIP: '#6b7280',
  Evaluated: '#f59e0b', Responded: '#06b6d4',
}[s] || '#94a3b8');

// ── Build status bars ─────────────────────────────────────────────────
const statusBars = Object.entries(statusCounts)
  .sort((a, b) => b[1] - a[1])
  .map(([s, n]) => `
    <div class="stat-row">
      <span class="badge" style="background:${badgeColor(s)}">${s}</span>
      <div class="bar-wrap"><div class="bar" style="width:${Math.min(100, n * 8)}%;background:${badgeColor(s)}"></div></div>
      <span class="count">${n}</span>
    </div>`).join('');

// ── Recent rows table ─────────────────────────────────────────────────
const recentRows = recent.map(r => `
  <tr>
    <td>${r.num}</td>
    <td>${r.date || ''}</td>
    <td><strong>${r.company}</strong></td>
    <td>${r.role}</td>
    <td>${r.score}</td>
    <td><span class="badge" style="background:${badgeColor(r.status)}">${r.status}</span></td>
  </tr>`).join('');

const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>Career Ops Dashboard</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #0f172a; color: #e2e8f0; padding: 24px; }
  h1 { font-size: 1.6rem; font-weight: 700; color: #f8fafc; margin-bottom: 4px; }
  .sub { color: #94a3b8; font-size: .85rem; margin-bottom: 24px; }
  .grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(160px, 1fr)); gap: 16px; margin-bottom: 24px; }
  .card { background: #1e293b; border-radius: 12px; padding: 20px; }
  .card .num { font-size: 2rem; font-weight: 800; color: #f8fafc; }
  .card .label { font-size: .8rem; color: #94a3b8; margin-top: 4px; }
  .section { background: #1e293b; border-radius: 12px; padding: 20px; margin-bottom: 20px; }
  .section h2 { font-size: 1rem; font-weight: 600; color: #cbd5e1; margin-bottom: 16px; }
  .stat-row { display: flex; align-items: center; gap: 10px; margin-bottom: 8px; }
  .badge { font-size: .72rem; padding: 2px 8px; border-radius: 99px; color: #fff; white-space: nowrap; }
  .bar-wrap { flex: 1; background: #334155; border-radius: 99px; height: 6px; }
  .bar { height: 6px; border-radius: 99px; transition: width .3s; }
  .count { font-size: .85rem; color: #94a3b8; width: 28px; text-align: right; }
  table { width: 100%; border-collapse: collapse; font-size: .85rem; }
  th { text-align: left; color: #64748b; font-weight: 500; padding: 6px 8px; border-bottom: 1px solid #334155; }
  td { padding: 8px; border-bottom: 1px solid #1e293b; color: #cbd5e1; }
  tr:hover td { background: #1e293b; }
  .pending-list { list-style: none; }
  .pending-list li { padding: 6px 0; border-bottom: 1px solid #334155; font-size: .83rem; color: #94a3b8; word-break: break-all; }
  .updated { color: #475569; font-size: .75rem; margin-top: 16px; text-align: right; }
</style>
</head>
<body>
<h1>Career Ops Pipeline</h1>
<p class="sub">Christiaan Verhoef &mdash; Last updated: ${now}</p>

<div class="grid">
  <div class="card"><div class="num">${rows.length}</div><div class="label">Total evaluated</div></div>
  <div class="card"><div class="num">${statusCounts['Applied'] || 0}</div><div class="label">Applied</div></div>
  <div class="card"><div class="num">${statusCounts['Interview'] || 0}</div><div class="label">In interview</div></div>
  <div class="card"><div class="num">${pending.length}</div><div class="label">Pending in pipeline</div></div>
  <div class="card"><div class="num">${highScore}</div><div class="label">Score &ge; 3.8</div></div>
  <div class="card"><div class="num">${avgScore}</div><div class="label">Avg score</div></div>
  <div class="card"><div class="num">${reps.length}</div><div class="label">Reports</div></div>
</div>

<div class="section">
  <h2>By Status</h2>
  ${statusBars || '<p style="color:#475569">No data yet</p>'}
</div>

<div class="section">
  <h2>Recent Activity</h2>
  <table>
    <thead><tr><th>#</th><th>Date</th><th>Company</th><th>Role</th><th>Score</th><th>Status</th></tr></thead>
    <tbody>${recentRows || '<tr><td colspan="6" style="color:#475569">No entries yet</td></tr>'}</tbody>
  </table>
</div>

<div class="section">
  <h2>Pipeline Queue (${pending.length} pending)</h2>
  <ul class="pending-list">
    ${pending.slice(0, 15).map(p => `<li>#${p.num} &mdash; <a href="${p.url}" style="color:#60a5fa" target="_blank">${p.url.slice(0, 80)}${p.url.length > 80 ? '...' : ''}</a></li>`).join('') || '<li style="color:#475569">Queue empty</li>'}
  </ul>
</div>

<p class="updated">Generated by Career Ops N8N pipeline &bull; ${now}</p>
</body></html>`;

return [{ json: { html, updated: now } }];

// Prepare GitHub PUT payload
const html = $('Build HTML').first().json.html;
const ghResponse = $input.first().json;

// SHA needed only if file exists; null = create new
const sha = ghResponse.body?.sha || null;
const b64 = Buffer.from(html, 'utf8').toString('base64');
const now = new Date().toISOString().split('T')[0];

return [{ json: {
  message: `dashboard: update ${now} [n8n]`,
  content: b64,
  sha,
} }];
